# ============================================================
# Security & Validation Utilities
# ============================================================
def generate_token(annotator_id: str) -> str:
    """Generate a secure API token for an annotator."""
    raw = f"{annotator_id}:{SECRET_KEY}:{time.time()}:{uuid.uuid4()}"
    token = hashlib.sha256(raw.encode()).hexdigest()
    return token


def validate_token(token: str) -> Optional[str]:
    """Validate token and return annotator_id or None."""
    return api_tokens.get(token)


def sanitize_label(label: str) -> str:
    """Sanitize and validate a label string."""
    if not isinstance(label, str):
        raise ValueError("Label must be a string")
    label = label.strip().lower()
    label = re.sub(r'[^\w\s\-]', '', label)
    label = re.sub(r'\s+', '_', label)
    if len(label) == 0:
        raise ValueError("Label cannot be empty")
    if len(label) > MAX_LABEL_LENGTH:
        raise ValueError(f"Label too long (max {MAX_LABEL_LENGTH} chars)")
    if ALLOWED_LABELS is not None and label not in ALLOWED_LABELS:
        raise ValueError(f"Label '{label}' not in allowed labels: {ALLOWED_LABELS}")
    return label


def validate_image(image_data: bytes) -> bool:
    """Validate that the data is a legitimate image."""
    try:
        img = Image.open(BytesIO(image_data))
        img.verify()
        return True
    except Exception:
        return False


# ============================================================
# Label Flip Detection
# ============================================================
def detect_label_flipping(image_id: str, annotator_id: str, new_label: str) -> dict:
    """
    Detect potential label flipping attacks.
    
    Label flipping is when a malicious annotator intentionally provides
    incorrect labels to poison the training data. We detect this by:
    1. Checking if annotator consistently disagrees with consensus
    2. Checking for sudden changes in labeling patterns
    3. Checking if annotator's labels are statistical outliers
    """
    result = {
        "is_suspicious": False,
        "reasons": [],
        "severity": "none"  # none, low, medium, high
    }
    
    stats = annotator_stats[annotator_id]
    
    # Check 1: Annotator's historical agreement rate
    if stats["total"] >= 10:
        agreement_rate = stats["agreed_with_consensus"] / stats["total"]
        if agreement_rate < ANNOTATOR_MIN_AGREEMENT_RATE:
            result["is_suspicious"] = True
            result["reasons"].append(
                f"Low agreement rate: {agreement_rate:.2%} over {stats['total']} annotations"
            )
            result["severity"] = "high"
    
    # Check 2: Check against current consensus for this image
    if image_id in consensus_store:
        consensus = consensus_store[image_id]
        if consensus["confidence"] >= 0.7 and new_label != consensus["label"]:
            # Strong consensus exists and this label disagrees
            existing_annotations = annotations_store.get(image_id, [])
            disagree_count = sum(
                1 for a in existing_annotations
                if a["label"] != consensus["label"] and a["annotator_id"] == annotator_id
            )
            if disagree_count > 0:
                result["is_suspicious"] = True
                result["reasons"].append(
                    f"Repeatedly disagrees with strong consensus ({consensus['confidence']:.0%}) on image {image_id}"
                )
                if result["severity"] == "none":
                    result["severity"] = "medium"
    
    # Check 3: Recent labeling pattern analysis
    recent = stats["recent_labels"][-LABEL_FLIP_DETECTION_WINDOW:]
    if len(recent) >= LABEL_FLIP_DETECTION_WINDOW // 2:
        # Check how many recent labels disagree with their respective consensus
        disagree_count = 0
        total_with_consensus = 0
        for entry in recent:
            img_id = entry["image_id"]
            if img_id in consensus_store:
                total_with_consensus += 1
                if entry["label"] != consensus_store[img_id]["label"]:
                    disagree_count += 1
        
        if total_with_consensus > 0:
            recent_disagree_rate = disagree_count / total_with_consensus
            if recent_disagree_rate > LABEL_FLIP_THRESHOLD:
                result["is_suspicious"] = True
                result["reasons"].append(
                    f"Recent disagreement rate: {recent_disagree_rate:.2%} "
                    f"({disagree_count}/{total_with_consensus} in last {len(recent)} annotations)"
                )
                result["severity"] = "high"
    
    # Check 4: Detect if annotator is targeting specific images with established consensus
    if stats["total"] >= 5:
        targeted_images = [
            entry for entry in recent
            if entry["image_id"] in consensus_store
            and consensus_store[entry["image_id"]]["confidence"] >= 0.8
            and entry["label"] != consensus_store[entry["image_id"]]["label"]
        ]
        if len(targeted_images) >= 3:
            result["is_suspicious"] = True
            result["reasons"].append(
                f"Appears to target high-confidence consensus images: {len(targeted_images)} suspicious annotations"
            )
            result["severity"] = "high"
    
    return result


def update_annotator_stats(annotator_id: str, image_id: str, label: str):
    """Update annotator statistics after an annotation."""
    stats = annotator_stats[annotator_id]
    stats["total"] += 1
    stats["recent_labels"].append({
        "image_id": image_id,
        "label": label,
        "timestamp": datetime.utcnow().isoformat()
    })
    # Keep only recent window
    if len(stats["recent_labels"]) > ANNOTATOR_TRUST_WINDOW:
        stats["recent_labels"] = stats["recent_labels"][-ANNOTATOR_TRUST_WINDOW:]
    
    # Check agreement with consensus
    if image_id in consensus_store:
        if label == consensus_store[image_id]["label"]:
            stats["agreed_with_consensus"] += 1


def compute_annotator_weight(annotator_id: str) -> float:
    """Compute weight for annotator based on trust score."""
    stats = annotator_stats[annotator_id]
    if stats["flagged"]:
        return 0.0  # Completely exclude flagged annotators
    if stats["total"] < 3:
        return 0.5  # New annotators get reduced weight
    agreement_rate = stats["agreed_with_consensus"] / max(stats["total"], 1)
    # Weight between 0.1 and 1.0 based on agreement
    return max(0.1, min(1.0, agreement_rate + 0.3))


# ============================================================
# Majority Voting Aggregation
# ============================================================
def compute_consensus(image_id: str) -> Optional[dict]:
    """
    Compute consensus label using weighted majority voting.
    Excludes annotations from flagged annotators.
    """
    if image_id not in annotations_store:
        return None
    
    image_annotations = annotations_store[image_id]
    if len(image_annotations) < MIN_ANNOTATIONS_FOR_CONSENSUS:
        return None
    
    # Weighted voting
    weighted_votes = defaultdict(float)
    total_weight = 0.0
    valid_votes = 0
    
    for ann in image_annotations:
        annotator_id = ann["annotator_id"]
        label = ann["label"]
        
        # Skip flagged annotators
        if annotator_stats[annotator_id]["flagged"]:
            continue
        
        weight = compute_annotator_weight(annotator_id)
        weighted_votes[label] += weight
        total_weight += weight
        valid_votes += 1
    
    if total_weight == 0 or valid_votes == 0:
        return None
    
    # Find majority
    best_label = max(weighted_votes, key=weighted_votes.get)
    confidence = weighted_votes[best_label] / total_weight
    
    if confidence >= MAJORITY_THRESHOLD:
        consensus = {
            "label": best_label,
            "confidence": confidence,
            "vote_count": valid_votes,
            "total_votes": len(image_annotations),
            "excluded_votes": len(image_annotations) - valid_votes,
            "computed_at": datetime.utcnow().isoformat()
        }
        consensus_store[image_id] = consensus
        return consensus
    
    return None


def recompute_all_consensus():
    """Recompute consensus for all images (e.g., after flagging an annotator)."""
    for image_id in list(annotations_store.keys()):
        compute_consensus(image_id)


# ============================================================
# Model Training
# ============================================================
class LabeledImageDataset(Dataset):
    """Dataset for training on consensus-labeled images."""
    
    def __init__(self, image_ids, labels, label_to_idx, image_store_ref):
        self.image_ids = image_ids
        self.labels = labels
        self.label_to_idx = label_to_idx
        self.image_store_ref = image_store_ref
        self.transform = transforms.Compose([
            transforms.Resize((224, 224)),
            transforms.ToTensor(),
            transforms.Normalize(mean=[0.485, 0.456, 0.406],
                                 std=[0.229, 0.224, 0.225])
        ])
    
    def __len__(self):
        return len(self.image_ids)
    
    def __getitem__(self, idx):
        image_id = self.image_ids[idx]
        label = self.labels[idx]
        
        image_data = self.image_store_ref[image_id]["data"]
        image = Image.open(BytesIO(image_data)).convert("RGB")
        image = self.transform(image)
        
        label_idx = self.label_to_idx[label]
        return image, label_idx


def train_model_on_consensus(min_confidence: float = 0.6, epochs: int = 10, 
                              learning_rate: float = 0.001, batch_size: int = 32):
    """Train a model on consensus-labeled data. No validation split - trains on all data."""
    
    with data_lock:
        # Collect training data: only use high-confidence consensus labels
        training_image_ids = []
        training_labels = []
        
        for image_id, consensus in consensus_store.items():
            if consensus["confidence"] >= min_confidence and image_id in image_store:
                training_image_ids.append(image_id)
                training_labels.append(consensus["label"])
        
        if len(training_image_ids) == 0:
            return {"error": "No training data available", "status": "failed"}
        
        # Build label mapping
        unique_labels = sorted(set(training_labels))
        if len(unique_labels) < 2:
            return {"error": "Need at least 2 classes to train", "status": "failed"}
        
        label_to_idx = {label: idx for idx, label in enumerate(unique_labels)}
        idx_to_label = {idx: label for label, idx in label_to_idx.items()}
    
    logger.info(f"Training on {len(training_image_ids)} images with {len(unique_labels)} classes")
    
    # Create dataset and dataloader
    dataset = LabeledImageDataset(
        training_image_ids, training_labels, label_to_idx, image_store
    )
    dataloader = DataLoader(dataset, batch_size=batch_size, shuffle=True, num_workers=0)
    
    # Initialize model (ResNet18 with custom head)
    device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
    model = models.resnet18(weights=None)
    model.fc = nn.Linear(model.fc.in_features, len(unique_labels))
    model = model.to(device)
    
    criterion = nn.CrossEntropyLoss()
    optimizer = optim.Adam(model.parameters(), lr=learning_rate)
    
    # Training loop - no validation, train on all consensus data
    model.train()
    training_history = []
    
    for epoch in range(epochs):
        running_loss = 0.0
        correct = 0
        total = 0
        
        for batch_images, batch_labels in dataloader:
            batch_images = batch_images.to(device)
            batch_labels = batch_labels.to(device)
            
            optimizer.zero_grad()
            outputs = model(batch_images)
            loss = criterion(outputs, batch_labels)
            loss.backward()
            optimizer.step()
            
            running_loss += loss.item() * batch_images.size(0)
            _, predicted = torch.max(outputs, 1)
            total += batch_labels.size(0)
            correct += (predicted == batch_labels).sum().item()
        
        epoch_loss = running_loss / total
        epoch_acc = correct / total
        training_history.append({
            "epoch": epoch + 1,
            "loss": round(epoch_loss, 4),
            "accuracy": round(epoch_acc, 4)
        })
        logger.info(f"Epoch {epoch+1}/{epochs} - Loss: {epoch_loss:.4f}, Acc: {epoch_acc:.4f}")
    
    # Save model state
    with data_lock:
        model_state["model"] = model
        model_state["label_to_idx"] = label_to_idx
        model_state["idx_to_label"] = idx_to_label
        model_state["trained_at"] = datetime.utcnow().isoformat()
        model_state["num_samples"] = len(training_image_ids)
        model_state["training_in_progress"] = False
    
    return {
        "status": "completed",
        "num_samples": len(training_image_ids),
        "num_classes": len(unique_labels),
        "classes": unique_labels,
        "epochs": epochs,
        "history": training_history,
        "trained_at": model_state["trained_at"]
    }


