@app.route("/api/annotators/register", methods=["POST"])
def register_annotator():
    """Register a new annotator and get an API token."""
    data = request.get_json()
    if not data or "annotator_id" not in data:
        return jsonify({"error": "annotator_id required"}), 400
    
    annotator_id = str(data["annotator_id"]).strip()
    if not annotator_id or len(annotator_id) > 100:
        return jsonify({"error": "Invalid annotator_id"}), 400
    
    # Check if already registered
    for token, aid in api_tokens.items():
        if aid == annotator_id:
            return jsonify({
                "annotator_id": annotator_id,
                "token": token,
                "message": "Already registered"
            })
    
    token = generate_token(annotator_id)
    with data_lock:
        api_tokens[token] = annotator_id
    
    return jsonify({
        "annotator_id": annotator_id,
        "token": token,
        "message": "Registered successfully"
    }), 201


@app.route("/api/images/upload", methods=["POST"])
def upload_image():
    """Upload an image for labeling."""
    token = request.headers.get("Authorization", "").replace("Bearer ", "")
    annotator_id = validate_token(token)
    if not annotator_id:
        return jsonify({"error": "Unauthorized"}), 401
    
    if "image" not in request.files:
        return jsonify({"error": "No image file provided"}), 400
    
    file = request.files["image"]
    image_data = file.read()
    
    if not validate_image(image_data):
        return jsonify({"error": "Invalid image file"}), 400
    
    image_id = str(uuid.uuid4())
    
    with data_lock:
        image_store[image_id] = {
            "data": image_data,
            "filename": file.filename,
            "uploaded_at": datetime.utcnow().isoformat(),
            "uploaded_by": annotator_id
        }
    
    return jsonify({
        "image_id": image_id,
        "filename": file.filename,
        "message": "Image uploaded successfully"
    }), 201


@app.route("/api/images/<image_id>/annotate", methods=["POST"])
def annotate_image(image_id):
    """Submit a label annotation for an image."""
    token = request.headers.get("Authorization", "").replace("Bearer ", "")
    annotator_id = validate_token(token)
    if not annotator_id:
        return jsonify({"error": "Unauthorized"}), 401
    
    if image_id not in image_store:
        return jsonify({"error": "Image not found"}), 404
    
    data = request.get_json()
    if not data or "label" not in data:
        return jsonify({"error": "label required"}), 400
    
    try:
        label = sanitize_label(data["label"])
    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    
    with data_lock:
        # Check if annotator is flagged
        if annotator_stats[annotator_id]["flagged"]:
            return jsonify({
                "error": "Your account has been flagged for suspicious activity. "
                         "Annotations are not accepted.",
                "flagged": True
            }), 403
        
        # Check max annotations per image
        if len(annotations_store[image_id]) >= MAX_LABELS_PER_IMAGE:
            return jsonify({"error": "Maximum annotations reached for this image"}), 400
        
        # Check for duplicate annotation from same annotator
        existing = [
            a for a in annotations_store[image_id]
            if a["annotator_id"] == annotator_id
        ]
        if existing:
            return jsonify({
                "error": "You have already annotated this image",
                "existing_annotation": existing[0]
            }), 409
        
        # === LABEL FLIP DETECTION ===
        flip_detection = detect_label_flipping(image_id, annotator_id, label)
        
        if flip_detection["is_suspicious"] and flip_detection["severity"] == "high":
            # Flag the annotator
            annotator_stats[annotator_id]["flagged"] = True
            annotator_stats[annotator_id]["flags"].append({
                "timestamp": datetime.utcnow().isoformat(),
                "image_id": image_id,
                "attempted_label": label,
                "reasons": flip_detection["reasons"]
            })
            
            label_flip_log.append({
                "annotator_id": annotator_id,
                "image_id": image_id,
                "attempted_label": label,
                "severity": flip_detection["severity"],
                "reasons": flip_detection["reasons"],
                "timestamp": datetime.utcnow().isoformat(),
                "action": "blocked_and_flagged"
            })
            
            logger.warning(
                f"LABEL FLIP DETECTED: Annotator {annotator_id} flagged. "
                f"Reasons: {flip_detection['reasons']}"
            )
            
            # Recompute consensus excluding this annotator
            recompute_all_consensus()
            
            return jsonify({
                "error": "Annotation rejected due to suspicious activity",
                "flagged": True,
                "reasons": flip_detection["reasons"]
            }), 403
        
        # Record annotation
        annotation_id = str(uuid.uuid4())
        annotation = {
            "annotation_id": annotation_id,
            "annotator_id": annotator_id,
            "label": label,
            "timestamp": datetime.utcnow().isoformat()
        }
        annotations_store[image_id].append(annotation)
        
        # Update annotator stats
        update_annotator_stats(annotator_id, image_id, label)
        
        # Recompute consensus for this image
        consensus = compute_consensus(image_id)
        
        # Log warning for medium severity
        if flip_detection["is_suspicious"] and flip_detection["severity"] == "medium":
            label_flip_log.append({
                "annotator_id": annotator_id,
                "image_id": image_id,
                "attempted_label": label,
                "severity": flip_detection["severity"],
                "reasons": flip_detection["reasons"],
                "timestamp": datetime.utcnow().isoformat(),
                "action": "accepted_with_warning"
            })
            logger.warning(
                f"SUSPICIOUS ANNOTATION: Annotator {annotator_id} on image {image_id}. "
                f"Reasons: {flip_detection['reasons']}"
            )
    
    response = {
        "annotation_id": annotation_id,
        "image_id": image_id,
        "label": label,
        "message": "Annotation recorded"
    }
    
    if flip_detection["is_suspicious"]:
        response["warning"] = "Your annotation pattern has been noted"
    
    if consensus:
        response["current_consensus"] = consensus
    
    return jsonify(response), 201


