@app.route("/api/images/<image_id>/consensus", methods=["GET"])
def get_consensus(image_id):
    """Get the consensus label for an image."""
    token = request.headers.get("Authorization", "").replace("Bearer ", "")
    annotator_id = validate_token(token)
    if not annotator_id:
        return jsonify({"error": "Unauthorized"}), 401
    
    if image_id not in image_store:
        return jsonify({"error": "Image not found"}), 404
    
    with data_lock:
        consensus = compute_consensus(image_id)
    
    if consensus is None:
        return jsonify({
            "image_id": image_id,
            "consensus": None,
            "message": f"Need at least {MIN_ANNOTATIONS_FOR_CONSENSUS} annotations for consensus"
        })
    
    return jsonify({
        "image_id": image_id,
        "consensus": consensus
    })


