@app.route("/api/model/train", methods=["POST"])
def train_model():
    """Trigger model training on consensus-labeled data."""
    token = request.headers.get("Authorization", "").replace("Bearer ", "")
    annotator_id = validate_token(token)
    if not annotator_id:
        return jsonify({"error": "Unauthorized"}), 401
    
    data = request.get_json() or {}
    min_confidence = data.get("min_confidence", 0.6)
    epochs = data.get("epochs", 10)
    learning_rate = data.get("learning_rate", 0.001)
    batch_size = data.get("batch_size", 32)
    
    # Validate parameters
    if not (0.5 <= min_confidence <= 1.0):
        return jsonify({"error": "min_confidence must be between 0.5 and 1.0"}), 400
    if not (1 <= epochs <= 100):
        return jsonify({"error": "epochs must be between 1 and 100"}), 400
    if not (1e-5 <= learning_rate <= 1.0):
        return jsonify({"error": "Invalid learning rate"}), 400
    
    if model_state["training_in_progress"]:
        return jsonify({"error": "Training already in progress"}), 409
    
    model_state["training_in_progress"] = True
    
    # Train in a separate thread
    def _train():
        try:
            result = train_model_on_consensus(
                min_confidence=min_confidence,
                epochs=epochs,
                learning_rate=learning_rate,
                batch_size=batch_size
            )
            logger.info(f"Training completed: {result}")
        except Exception as e:
            logger.error(f"Training failed: {e}")
            model_state["training_in_progress"] = False
    
    thread = threading.Thread(target=_train)
    thread.start()
    
    return jsonify({
        "message": "Training started",
        "parameters": {
            "min_confidence": min_confidence,
            "epochs": epochs,
            "learning_rate": learning_rate,
            "batch_size": batch_size
        }
    }), 202


@app.route("/api/model/train/sync", methods=["POST"])
def train_model_sync():
    """Trigger model training synchronously (for testing)."""
    token = request.headers.get("Authorization", "").replace("Bearer ", "")
    annotator_id = validate_token(token)
    if not annotator_id:
        return jsonify({"error": "Unauthorized"}), 401
    
    data = request.get_json() or {}
    min_confidence = data.get("min_confidence", 0.6)
    epochs = data.get("epochs", 10)
    learning_rate = data.get("learning_rate", 0.001)
    batch_size = data.get("batch_size", 32)
    
    if model_state["training_in_progress"]:
        return jsonify({"error": "Training already in progress"}), 409
    
    model_state["training_in_progress"] = True
    
    try:
        result = train_model_on_consensus(
            min_confidence=min_confidence,
            epochs=epochs,
            learning_rate=learning_rate,
            batch_size=batch_size
        )
        return jsonify(result)
    except Exception as e:
        model_state["training_in_progress"] = False
        return jsonify({"error": str(e), "status": "failed"}), 500


@app.route("/api/model/status", methods=["GET"])
def model_status():
    """Get the current model training status."""
    token = request.headers.get("Authorization", "").replace("Bearer ", "")
    annotator_id = validate_token(token)
