@app.route("/api/security/unflag-annotator", methods=["POST"])
def unflag_annotator():
    """Unflag an annotator (admin action)."""
    token = request.headers.get("Authorization", "").replace("Bearer ", "")
    requesting_annotator = validate_token(token)
    if not requesting_annotator:
        return jsonify({"error": "Unauthorized"}), 401
    
    data = request.get_json()
    if not data or "annotator_id" not in data:
        return jsonify({"error": "annotator_id required"}), 400
    
    target_id = data["annotator_id"]
    
    with data_lock:
        if target_id not in annotator_stats:
            return jsonify({"error": "Annotator not found"}), 404
        
        annotator_stats[target_id]["flagged"] = False
        annotator_stats[target_id]["flags"].append({
            "timestamp": datetime.utcnow().isoformat(),
            "action": "unflagged",
            "by": requesting_annotator
        })
        
        # Recompute consensus since this annotator's votes now count again
        recompute_all_consensus()
    
    return jsonify({
        "message": f"Annotator {target_id} has been unflagged",
        "annotator_id": target_id
    })


@app.route("/api/stats", methods=["GET"])
def get_system_stats():
    """Get overall system statistics."""
    token = request.headers.get("Authorization", "").replace("Bearer ", "")
    annotator_id = validate_token(token)
    if not annotator_id:
        return jsonify({"error": "Unauthorized"}), 401
    
    with data_lock:
        total_annotations = sum(len(anns) for anns in annotations_store.values())
        total_annotators = len(set(
            ann["annotator_id"]
            for anns in annotations_store.values()
            for ann in anns
        ))
        flagged_count = sum(
            1 for stats in annotator_stats.values() if stats["flagged"]
        )
        
        label_distribution = Counter()
        for consensus in consensus_store.values():
            label_distribution[consensus["label"]] += 1
    
    return jsonify({
        "total_images": len(image_store),
        "total_annotations": total_annotations,
        "total_annotators": total_annotators,
        "images_with_consensus": len(consensus_store),
        "flagged_annotators": flagged_count,
        "label_flip_incidents": len(label_flip_log),
        "label_distribution": dict(label_distribution),
        "model_trained": model_state["model"] is not None,
        "model_trained_at": model_state["trained_at"]
    })


@app.route("/api/images", methods=["GET"])
def list_images():
    """List all images with their annotation status."""
    token = request.headers.get("Authorization", "").replace("Bearer ", "")
    annotator_id = validate_token(token)
    if not annotator_id:
        return jsonify({"error": "Unauthorized"}), 401
    
    with data_lock:
        images = []
        for image_id, img_data in image_store.items():
            ann_count = len(annotations_store.get(image_id, []))
            consensus = consensus_store.get(image_id)
            images.append({
                "image_id": image_id,
                "filename": img_data["filename"],
                "uploaded_at": img_data["uploaded_at"],
                "annotation_count": ann_count,
                "has_consensus": consensus is not None,
                "consensus_label": consensus["label"] if consensus else None,
                "consensus_confidence": consensus["confidence"] if consensus else None
            })
    
    return jsonify({
        "total": len(images),
        "images": images
    })


